local function solveCase(s) local stack={-1}; local best=0; for i=1,#s do local ch=s:sub(i,i); if ch=='(' then stack[#stack+1]=i-1 else table.remove(stack); if #stack==0 then stack[#stack+1]=i-1 else if i-1-stack[#stack] > best then best=i-1-stack[#stack] end end end end; return best end
local lines={} for line in io.lines() do table.insert(lines,line) end if #lines==0 or lines[1]:match('^%s*$') then os.exit() end local idx,t=2,tonumber(lines[1]); local out={} for _=1,t do local n=tonumber(lines[idx]); idx=idx+1; local s=''; if n>0 then s=lines[idx]; idx=idx+1 end; out[#out+1]=tostring(solveCase(s)) end io.write(table.concat(out,'\n'))
